package com.evolua.subscription.infrastructure.persistence; import com.evolua.subscription.domain.Subscription; import com.evolua.subscription.domain.SubscriptionRepository; import java.util.List; import org.springframework.stereotype.Repository; @Repository public class SubscriptionPersistenceAdapter implements SubscriptionRepository { private final SubscriptionJpaRepository repository; public SubscriptionPersistenceAdapter(SubscriptionJpaRepository repository) { this.repository = repository; } public Subscription save(Subscription item) { SubscriptionEntity entity = new SubscriptionEntity(); entity.setId(item.id()); entity.setUserId(item.userId()); entity.setPlanCode(item.planCode()); entity.setStatus(item.status()); entity.setBillingCycle(item.billingCycle()); entity.setPremium(item.premium()); entity.setCreatedAt(item.createdAt()); SubscriptionEntity saved = repository.save(entity); return new Subscription(saved.getId(), saved.getUserId(), saved.getPlanCode(), saved.getStatus(), saved.getBillingCycle(), saved.getPremium(), saved.getCreatedAt()); } public List<Subscription> findAllByUserId(String userId) { return repository.findAllByUserId(userId).stream().map(saved -> new Subscription(saved.getId(), saved.getUserId(), saved.getPlanCode(), saved.getStatus(), saved.getBillingCycle(), saved.getPremium(), saved.getCreatedAt())).toList(); } }
